1	/**
2	 * Synthesizer AudioWorklet processor.
3	 * Runs on the audio rendering thread — zero allocations in process().
4	 *
5	 * Architecture: 16 fixed voices, each with:
6	 * - 2 PolyBLEP oscillators
7	 * - Biquad filter (LP/HP/BP)
8	 * - ADSR amplitude envelope
9	 * - ADSR filter envelope
10	 * Shared: 2 LFOs, hardwired modulation matrix.
11	 *
12	 * INV-3/NFR-14: Zero-allocation process().
13	 * MIT-H4-5: Oldest-steal with 5ms crossfade.
14	 * MIT-H4-6: 2ms minimum release time.
15	 * R-STA-05: Legato mode with pitch glide.
16	 */
17	
18	import { createPolyBLEPOsc, type PolyBLEPOsc } from "./dsp/polyblep";
19	import {
20	  createADSREnvelope,
21	  type ADSREnvelope,
22	  type ADSRParams,
23	} from "./dsp/adsr";
24	import {
25	  computeBiquadCoeffs,
26	  createBiquadFilter,
27	  type BiquadFilter,
28	} from "./dsp/biquad-coeffs";
29	import { createLFO, type LFO } from "./dsp/lfo";
30	import {
31	  createVoiceAllocator,
32	  type VoiceAllocator,
33	  MAX_VOICES,
34	} from "./dsp/voice-allocator";
35	import {
36	  midiToFreq,
37	  WAVEFORM_TYPES,
38	  FILTER_TYPES,
39	  LFO_SHAPES,
40	  type SynthVoiceCommand,
41	  type SynthParameterMap,
42	  DEFAULT_SYNTH_PARAMS,
43	} from "./synth-types";
44	
45	// ─── AudioWorklet globals ───
46	declare const sampleRate: number;
47	declare class AudioWorkletProcessor {
48	  readonly port: MessagePort;
49	  constructor();
50	  process(
51	    inputs: Float32Array[][],
52	    outputs: Float32Array[][],
53	    parameters: Record<string, Float32Array>,
54	  ): boolean;
55	}
56	declare function registerProcessor(
57	  name: string,
58	  ctor: typeof AudioWorkletProcessor,
59	): void;
60	
61	// ─── Per-Voice State (pre-allocated) ───
62	
63	type VoiceData = {
64	  osc1: PolyBLEPOsc;
65	  osc2: PolyBLEPOsc;
66	  ampEnv: ADSREnvelope;
67	  filterEnv: ADSREnvelope;
68	  filter: BiquadFilter;
69	  targetFreq: number;
70	  currentFreq: number;
71	  velocity: number;
72	};
73	
74	function createVoiceData(): VoiceData {
75	  return {
76	    osc1: createPolyBLEPOsc("saw"),
77	    osc2: createPolyBLEPOsc("saw"),
78	    ampEnv: createADSREnvelope(),
79	    filterEnv: createADSREnvelope(),
80	    filter: createBiquadFilter("lowpass"),
81	    targetFreq: 440,
82	    currentFreq: 440,
83	    velocity: 0,
84	  };
85	}
86	
87	/** Safe access to pre-allocated arrays */
88	function at<T>(arr: T[], i: number): T {
89	  const val = arr[i];
90	  if (val === undefined) throw new Error("Index out of bounds");
91	  return val;
92	}
93	
94	class SynthProcessor extends AudioWorkletProcessor {
95	  private allocator: VoiceAllocator;
96	  private voiceData: VoiceData[];
97	  private lfo1: LFO;
98	  private lfo2: LFO;
99	  private params: SynthParameterMap;
100	  // Pre-allocated ADSR params (S2-3: avoid per-quantum allocation)
101	  private ampParams: ADSRParams;
102	  private filterParams: ADSRParams;
103	  private alive = true;
104	
105	  constructor() {
106	    super();
107	
108	    this.allocator = createVoiceAllocator();
109	    this.voiceData = Array.from({ length: MAX_VOICES }, () =>
110	      createVoiceData(),
111	    );
112	    this.lfo1 = createLFO("sine");
113	    this.lfo2 = createLFO("sine");
114	    this.params = { ...DEFAULT_SYNTH_PARAMS };
115	    this.ampParams = { attack: 0, decay: 0, sustain: 0, release: 0 };
116	    this.filterParams = { attack: 0, decay: 0, sustain: 0, release: 0 };
117	
118	    this.port.onmessage = (e: MessageEvent) => {
119	      this.handleMessage(e.data as SynthVoiceCommand);
120	    };
121	  }
122	
123	  private handleMessage(cmd: SynthVoiceCommand): void {
124	    switch (cmd.type) {
125	      case "noteOn": {
126	        const legato = cmd.legato;
127	        const idx = this.allocator.noteOn(cmd.note, cmd.velocity, legato);
128	        const voice = at(
129	          this.allocator.voices as unknown[],
130	          idx,
131	        ) as (typeof this.allocator.voices)[number];
132	
133	        // If voice is stealing, don't touch oscillators/envelopes yet —
134	        // the old voice continues rendering during the 5ms crossfade.
135	        // The processor will apply the new note when steal completes.
136	        if (voice.state === "stealing") {
137	          return;
138	        }
139	
140	        this.applyNoteOn(idx, cmd.note, cmd.velocity, legato);
141	        break;
142	      }
143	
144	      case "noteOff": {
145	        const idx = this.allocator.noteOff(cmd.note);
146	        if (idx >= 0) {
147	          const vd = at(this.voiceData, idx);
148	          vd.ampEnv.release();
149	          vd.filterEnv.release();
