1	/**
2	 * PolyBLEP (Polynomial Bandlimited Step) antialiased oscillator.
3	 * Corrects discontinuities in naive waveforms to suppress aliasing.
4	 * O(1) per sample, no lookup tables, pitch-agile.
5	 */
6	
7	/** Waveform types supported by the PolyBLEP oscillator */
8	export type WaveformType = "sine" | "saw" | "square" | "triangle";
9	
10	/** PolyBLEP correction term for a discontinuity at phase = 0 */
11	function polyblep(t: number, dt: number): number {
12	  if (t < dt) {
13	    const u = t / dt;
14	    return u + u - u * u - 1;
15	  }
16	  if (t > 1 - dt) {
17	    const u = (t - 1) / dt;
18	    return u * u + u + u + 1;
19	  }
20	  return 0;
21	}
22	
23	/**
24	 * Stateful PolyBLEP oscillator.
25	 * Call `next()` once per sample to get the output in [-1, 1].
26	 * Mutates phase internally — zero-allocation in the hot path.
27	 */
28	export type PolyBLEPOsc = {
29	  phase: number;
30	  type: WaveformType;
31	  /** Advance one sample. Returns output in [-1, 1]. */
32	  next(frequency: number, sampleRate: number): number;
33	  /** Reset phase (e.g. for hard sync). */
34	  reset(): void;
35	};
36	
37	export function createPolyBLEPOsc(type: WaveformType = "saw"): PolyBLEPOsc {
38	  let phase = 0;
39	  // Leaky integrator state for triangle wave
40	  let triState = 0;
41	
42	  const osc: PolyBLEPOsc = {
43	    get phase() {
44	      return phase;
45	    },
46	    set phase(p: number) {
47	      phase = p;
48	    },
49	    type,
50	
51	    next(frequency: number, sampleRate: number): number {
52	      const dt = frequency / sampleRate; // phase increment per sample
53	
54	      let out: number;
55	      switch (osc.type) {
56	        case "sine":
57	          out = Math.sin(2 * Math.PI * phase);
58	          break;
59	
60	        case "saw": {
61	          // Naive sawtooth: ramp from -1 to 1
62	          out = 2 * phase - 1;
63	          out -= polyblep(phase, dt);
64	          break;
65	        }
66	
67	        case "square": {
68	          // Naive square: +1 for first half, -1 for second
69	          out = phase < 0.5 ? 1 : -1;
70	          out += polyblep(phase, dt);
71	          out -= polyblep((phase + 0.5) % 1, dt);
72	          break;
73	        }
74	
75	        case "triangle": {
76	          // Integrated square wave -> triangle via leaky integrator
77	          let sq = phase < 0.5 ? 1 : -1;
78	          sq += polyblep(phase, dt);
79	          sq -= polyblep((phase + 0.5) % 1, dt);
80	          // Integrate with leak
81	          triState = dt * sq + (1 - dt) * triState;
82	          // Scale and clamp to [-1, 1]
83	          out = Math.max(-1, Math.min(1, triState * 4));
84	          break;
85	        }
86	
87	        default:
88	          out = 0;
89	      }
90	
91	      // Advance phase
92	      phase += dt;
93	      if (phase >= 1) phase -= 1;
94	
95	      return out;
96	    },
97	
98	    reset(): void {
99	      phase = 0;
100	      triState = 0;
101	    },
102	  };
103	
104	  return osc;
105	}
