import { describe, it, expect, vi, beforeEach } from "vitest";
import { createDrumKit } from "./drum-kit";
import { DRUM_INSTRUMENTS, DEFAULT_INSTRUMENT_PARAMS } from "./drum-types";
import type { DrumInstrumentId } from "./drum-types";

// Minimal AudioContext mock for testing the drum kit wiring
function createMockAudioContext(): AudioContext {
  const gainNode = () => ({
    gain: { value: 1, setValueAtTime: vi.fn(), linearRampToValueAtTime: vi.fn(), exponentialRampToValueAtTime: vi.fn(), cancelScheduledValues: vi.fn() },
    connect: vi.fn(),
    disconnect: vi.fn(),
  });

  const filterNode = () => ({
    frequency: { value: 1000, setValueAtTime: vi.fn() },
    type: "lowpass",
    Q: { value: 1 },
    connect: vi.fn(),
    disconnect: vi.fn(),
  });

  const sourceNode = () => ({
    buffer: null,
    playbackRate: { value: 1, setValueAtTime: vi.fn() },
    connect: vi.fn(),
    disconnect: vi.fn(),
    start: vi.fn(),
    stop: vi.fn(),
    addEventListener: vi.fn(),
  });

  return {
    currentTime: 0,
    sampleRate: 48000,
    createGain: vi.fn(() => gainNode()),
    createBiquadFilter: vi.fn(() => filterNode()),
    createBufferSource: vi.fn(() => sourceNode()),
    decodeAudioData: vi.fn(),
  } as unknown as AudioContext;
}

function createSilentBuffer(ctx: AudioContext): AudioBuffer {
  return {
    length: 4800,
    sampleRate: 48000,
    duration: 0.1,
    numberOfChannels: 1,
    getChannelData: () => new Float32Array(4800),
    copyFromChannel: vi.fn(),
    copyToChannel: vi.fn(),
  } as unknown as AudioBuffer;
}

describe("createDrumKit", () => {
  let ctx: AudioContext;
  let samples: Map<DrumInstrumentId, AudioBuffer>;

  beforeEach(() => {
    ctx = createMockAudioContext();
    samples = new Map();
    for (const inst of DRUM_INSTRUMENTS) {
      samples.set(inst.id, createSilentBuffer(ctx));
    }
  });

  it("creates a drum kit", () => {
    const kit = createDrumKit(ctx, samples);
    expect(kit).toBeDefined();
    expect(kit.trigger).toBeTypeOf("function");
    expect(kit.setParam).toBeTypeOf("function");
    expect(kit.dispose).toBeTypeOf("function");
  });

  it("trigger creates a buffer source and starts it", () => {
    const kit = createDrumKit(ctx, samples);
    kit.trigger("bd", 0.1, 0.8);
    expect(ctx.createBufferSource).toHaveBeenCalled();
    expect(ctx.createBiquadFilter).toHaveBeenCalled();
    expect(ctx.createGain).toHaveBeenCalled();
  });

  it("trigger with flam schedules a second hit", () => {
    const kit = createDrumKit(ctx, samples);
    const callsBefore = (ctx.createBufferSource as ReturnType<typeof vi.fn>).mock.calls.length;
    kit.trigger("sd", 0.1, 0.8, 15);
    const callsAfter = (ctx.createBufferSource as ReturnType<typeof vi.fn>).mock.calls.length;
    // Flam = two buffer sources
    expect(callsAfter - callsBefore).toBe(2);
  });

  it("hi-hat mutual exclusivity: CH cuts OH", () => {
    const kit = createDrumKit(ctx, samples);
    // Trigger open hi-hat
    kit.trigger("oh", 0.1, 0.8);
    // Trigger closed hi-hat shortly after — should cut off OH
    kit.trigger("ch", 0.15, 0.8);
    // Both should create sources (the OH source gets stopped)
    expect(ctx.createBufferSource).toHaveBeenCalled();
  });

  it("setParam updates instrument params", () => {
    const kit = createDrumKit(ctx, samples);
    // Should not throw
    kit.setParam("bd", "tone", 2000);
    kit.setParam("bd", "decay", 0.8);
    kit.setParam("bd", "tune", 1.5);
    kit.setParam("bd", "volume", 0.5);
  });

  it("connectToMixer wires output to mixer strip input", () => {
    const kit = createDrumKit(ctx, samples);
    const mockMixer = {
      getOrCreateStrip: vi.fn(() => ({
        inputGain: { connect: vi.fn() } as unknown as GainNode,
      })),
    };
    kit.connectToMixer(mockMixer as any, "drum-track");
    expect(mockMixer.getOrCreateStrip).toHaveBeenCalledWith("drum-track");
  });

  it("dispose disconnects output", () => {
    const kit = createDrumKit(ctx, samples);
    // Should not throw
    kit.dispose();
  });

  it("ignores trigger for missing sample", () => {
    const partialSamples = new Map<DrumInstrumentId, AudioBuffer>();
    partialSamples.set("bd", createSilentBuffer(ctx));
    const kit = createDrumKit(ctx, partialSamples);
    // Trigger an instrument with no sample — should not throw
    kit.trigger("sd", 0.1, 0.8);
  });

  it("accent boosts velocity", () => {
    const kit = createDrumKit(ctx, samples);
    // Trigger with full velocity (accent scenario)
    kit.trigger("sd", 0.1, 1.0);
    expect(ctx.createBufferSource).toHaveBeenCalled();
  });
});

