        }
        activeOH = null;
      }

      const voice = triggerOnce(instrumentId, time, velocity);

      // Track open hi-hat voice
      if (instrumentId === "oh" && voice) {
        activeOH = voice;
      }

      // Flam: trigger a second quieter hit offset by flamMs
      if (flamMs && flamMs > 0) {
