    render(<DrumMachinePanel {...props} />);
    const bdPad = screen.getByRole("button", { name: "Bass Drum" });
    fireEvent.pointerDown(bdPad);
    expect(props.onTriggerPad).toHaveBeenCalledWith("bd");
