import { describe, it, expect, vi, beforeEach } from "vitest";
import { createDrumKit } from "./drum-kit";
import { DRUM_INSTRUMENTS } from "./drum-types";
import type { DrumInstrumentId } from "./drum-types";
import type { MixerEngine } from "@audio/mixer/types";

function createMockAudioContext(): AudioContext {
  const gainNode = (): object => ({
    gain: { value: 1, setValueAtTime: vi.fn(), linearRampToValueAtTime: vi.fn(), exponentialRampToValueAtTime: vi.fn(), cancelScheduledValues: vi.fn() },
    connect: vi.fn(),
    disconnect: vi.fn(),
  });

  const filterNode = (): object => ({
    frequency: { value: 1000, setValueAtTime: vi.fn() },
    type: "lowpass",
    Q: { value: 1 },
    connect: vi.fn(),
    disconnect: vi.fn(),
  });

  const sourceNode = (): object => ({
    buffer: null,
    playbackRate: { value: 1, setValueAtTime: vi.fn() },
    connect: vi.fn(),
    disconnect: vi.fn(),
    start: vi.fn(),
    stop: vi.fn(),
    addEventListener: vi.fn(),
  });

  return {
    currentTime: 0,
    sampleRate: 48000,
    createGain: vi.fn(() => gainNode()),
    createBiquadFilter: vi.fn(() => filterNode()),
    createBufferSource: vi.fn(() => sourceNode()),
    decodeAudioData: vi.fn(),
  } as unknown as AudioContext;
}

function createSilentBuffer(_ctx: AudioContext): AudioBuffer {
  return {
    length: 4800,
    sampleRate: 48000,
    duration: 0.1,
    numberOfChannels: 1,
    getChannelData: () => new Float32Array(4800),
    copyFromChannel: vi.fn(),
    copyToChannel: vi.fn(),
  } as unknown as AudioBuffer;
}

describe("createDrumKit", () => {
  let ctx: AudioContext;
  let samples: Map<DrumInstrumentId, AudioBuffer>;

  beforeEach(() => {
    ctx = createMockAudioContext();
    samples = new Map();
    for (const inst of DRUM_INSTRUMENTS) {
      samples.set(inst.id, createSilentBuffer(ctx));
    }
  });

  it("creates a drum kit", () => {
    const kit = createDrumKit(ctx, samples);
    expect(kit).toBeDefined();
    expect(typeof kit.trigger).toBe("function");
    expect(typeof kit.setParam).toBe("function");
    expect(typeof kit.dispose).toBe("function");
  });

  it("trigger creates a buffer source and starts it", () => {
    const kit = createDrumKit(ctx, samples);
    kit.trigger("bd", 0.1, 0.8);
    expect(ctx.createBufferSource).toHaveBeenCalled();
    expect(ctx.createBiquadFilter).toHaveBeenCalled();
    expect(ctx.createGain).toHaveBeenCalled();
  });

  it("trigger with flam schedules a second hit", () => {
    const kit = createDrumKit(ctx, samples);
    const callsBefore = (ctx.createBufferSource as ReturnType<typeof vi.fn>).mock.calls.length;
    kit.trigger("sd", 0.1, 0.8, 15);
    const callsAfter = (ctx.createBufferSource as ReturnType<typeof vi.fn>).mock.calls.length;
    expect(callsAfter - callsBefore).toBe(2);
  });

  it("hi-hat mutual exclusivity: CH cuts OH", () => {
    const kit = createDrumKit(ctx, samples);
    kit.trigger("oh", 0.1, 0.8);
    kit.trigger("ch", 0.15, 0.8);
    expect(ctx.createBufferSource).toHaveBeenCalled();
  });

  it("setParam updates instrument params", () => {
    const kit = createDrumKit(ctx, samples);
    kit.setParam("bd", "tone", 2000);
    kit.setParam("bd", "decay", 0.8);
    kit.setParam("bd", "tune", 1.5);
    kit.setParam("bd", "volume", 0.5);
  });

  it("connectToMixer wires output to mixer strip input", () => {
    const kit = createDrumKit(ctx, samples);
    const mockMixer = {
      getOrCreateStrip: vi.fn(() => ({
        inputGain: { connect: vi.fn() } as unknown as GainNode,
      })),
    } as unknown as MixerEngine;
    kit.connectToMixer(mockMixer, "drum-track");
    expect(mockMixer.getOrCreateStrip).toHaveBeenCalledWith("drum-track");
  });

  it("dispose disconnects output", () => {
    const kit = createDrumKit(ctx, samples);
    kit.dispose();
  });

  it("ignores trigger for missing sample", () => {
    const partialSamples = new Map<DrumInstrumentId, AudioBuffer>();
    partialSamples.set("bd", createSilentBuffer(ctx));
    const kit = createDrumKit(ctx, partialSamples);
    kit.trigger("sd", 0.1, 0.8);
  });

  it("accent boosts velocity", () => {
    const kit = createDrumKit(ctx, samples);
    kit.trigger("sd", 0.1, 1.0);
    expect(ctx.createBufferSource).toHaveBeenCalled();
  });
});

/**
 * Sample-based drum kit engine.
 * Plays one-shot AudioBuffers through BiquadFilter + GainNode envelope.
 * Per-instrument Tone/Decay/Tune/Volume. Hi-hat mutual exclusivity.
 *
 * Uses native Web Audio nodes (per lesson L9ed0990ebe98f667).
 */

import type { MixerEngine } from "@audio/mixer/types";
import type { DrumInstrumentId, DrumInstrumentParams, DrumKit } from "./drum-types";
import { DEFAULT_INSTRUMENT_PARAMS } from "./drum-types";

type ActiveVoice = {
  source: AudioBufferSourceNode;
  gain: GainNode;
};

export function createDrumKit(
  ctx: AudioContext,
  samples: Map<DrumInstrumentId, AudioBuffer>,
): DrumKit {
  const output = ctx.createGain();
  const params = new Map<DrumInstrumentId, DrumInstrumentParams>();

  // Clone defaults
  for (const [id, defaults] of Object.entries(DEFAULT_INSTRUMENT_PARAMS)) {
    params.set(id as DrumInstrumentId, { ...defaults });
  }

  // Track active open hi-hat voice for mutual exclusivity
  let activeOH: ActiveVoice | null = null;

  function triggerOnce(
    instrumentId: DrumInstrumentId,
    time: number,
    velocity: number,
  ): ActiveVoice | null {
    const buffer = samples.get(instrumentId);
    if (!buffer) return null;

    const p = params.get(instrumentId);
    if (!p) return null;

    // AudioBufferSourceNode — sample playback
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.playbackRate.setValueAtTime(p.tune, time);

    // BiquadFilter — tone control (lowpass)
    const filter = ctx.createBiquadFilter();
    filter.type = "lowpass";
    filter.frequency.setValueAtTime(p.tone, time);

    // GainNode — volume envelope with decay
    const gain = ctx.createGain();
    const peakGain = p.volume * velocity;
    gain.gain.setValueAtTime(peakGain, time);
    gain.gain.exponentialRampToValueAtTime(0.001, time + p.decay);

    // Chain: source -> filter -> gain -> output
    source.connect(filter);
    filter.connect(gain);
    gain.connect(output);

    source.start(time);
    source.stop(time + p.decay + 0.01);

    // Clean up on ended
    source.addEventListener("ended", () => {
      source.disconnect();
      filter.disconnect();
      gain.disconnect();
    });

    return { source, gain };
  }

  const kit: DrumKit = {
    trigger(
      instrumentId: DrumInstrumentId,
      time: number,
      velocity: number,
      flamMs?: number,
    ): void {
      // Hi-hat mutual exclusivity: CH cuts OH
      if (instrumentId === "ch" && activeOH) {
        try {
          activeOH.gain.gain.cancelScheduledValues(time);
          activeOH.gain.gain.setValueAtTime(0, time);
          activeOH.source.stop(time + 0.001);
        } catch {
          // Source may already be stopped
        }
        activeOH = null;
      }

      const voice = triggerOnce(instrumentId, time, velocity);

      // Track open hi-hat voice
      if (instrumentId === "oh" && voice) {
        activeOH = voice;
      }

      // Flam: trigger a second quieter hit offset by flamMs
      if (flamMs && flamMs > 0) {
        triggerOnce(instrumentId, time + flamMs / 1000, velocity * 0.7);
      }
    },

    setParam(
      instrumentId: DrumInstrumentId,
      key: keyof DrumInstrumentParams,
      value: number,
    ): void {
      const p = params.get(instrumentId);
      if (!p) return;
      (p as Record<string, number>)[key] = value;
    },

    connectToMixer(mixer: MixerEngine, trackId: string): void {
      const strip = mixer.getOrCreateStrip(trackId);
      output.connect(strip.inputGain);
    },

    disconnectFromMixer(_mixer: MixerEngine, _trackId: string): void {
      output.disconnect();
    },

    dispose(): void {
      output.disconnect();
    },
  };

  return kit;
}

