41	export function createStepSequencer(
42	  onTrigger: (trigger: DrumTrigger) => void,
43	): StepSequencer {
44	  const patterns = new Map<string, DrumStep[]>();
45	  let activePatternName = "A";
46	
47	  // Initialize A and B
48	  patterns.set("A", createSteps());
49	  patterns.set("B", createSteps());
50	
51	  function createSteps(): DrumStep[] {
52	    return createEmptyPattern().steps.map((s) => ({ ...s, triggers: { ...s.triggers } }));
53	  }
54	
55	  function getActiveSteps(): DrumStep[] {
56	    let steps = patterns.get(activePatternName);
57	    if (!steps) {
58	      steps = createSteps();
59	      patterns.set(activePatternName, steps);
60	    }
61	    return steps;
62	  }
63	
64	  const seq: StepSequencer = {
65	    scheduleStep(stepIndex: number, time: number): void {
66	      const idx = stepIndex % STEPS_PER_PATTERN;
67	      const steps = getActiveSteps();
68	      const step = steps[idx];
69	      if (!step) return;
70	      const velocity = step.accent ? ACCENT_VELOCITY : NORMAL_VELOCITY;
71	
72	      for (const inst of DRUM_INSTRUMENTS) {
73	        if (step.triggers[inst.id]) {
74	          onTrigger({
75	            instrumentId: inst.id,
76	            time,
77	            velocity,
78	            flamMs: step.flamMs > 0 ? step.flamMs : undefined,
79	          });
80	        }
81	      }
82	    },
83	
84	    toggleStep(instrumentId: DrumInstrumentId, stepIndex: number): void {
85	      const steps = getActiveSteps();
86	      const idx = stepIndex % STEPS_PER_PATTERN;
87	      const step = steps[idx];
88	      if (!step) return;
89	      const newTriggers = { ...step.triggers };
90	      newTriggers[instrumentId] = !newTriggers[instrumentId];
91	      steps[idx] = { ...step, triggers: newTriggers };
92	    },
93	
94	    setAccent(stepIndex: number, accent: boolean): void {
95	      const steps = getActiveSteps();
96	      const idx = stepIndex % STEPS_PER_PATTERN;
97	      const step = steps[idx];
98	      if (!step) return;
99	      steps[idx] = { ...step, accent };
100	    },
101	
102	    setFlam(stepIndex: number, flamMs: number): void {
103	      const steps = getActiveSteps();
104	      const idx = stepIndex % STEPS_PER_PATTERN;
105	      const step = steps[idx];
106	      if (!step) return;
107	      steps[idx] = { ...step, flamMs };
108	    },
109	
110	    switchPattern(name: string): void {
111	      if (!patterns.has(name)) {
112	        patterns.set(name, createSteps());
113	      }
114	      activePatternName = name;
115	    },
116	
117	    getActivePatternName(): string {
118	      return activePatternName;
119	    },
120	
121	    getPattern(): DrumPattern {
122	      const steps = getActiveSteps();
123	      return { name: activePatternName, steps: steps.map((s) => ({ ...s, triggers: { ...s.triggers } })) };
124	    },
125	
126	    clearPattern(): void {
127	      patterns.set(activePatternName, createSteps());
128	    },
129	  };
130	
131	  return seq;
132	}
