1	/**
2	 * Types for the mixer audio engine.
3	 * Channel strips, master bus, insert chain infrastructure.
4	 */
5	
6	export type InsertSlot = {
7	  readonly id: string;
8	  readonly node: AudioNode | null; // null = empty slot
9	  readonly bypassed: boolean;
10	};
11	
12	export type ChannelStrip = {
13	  readonly trackId: string;
14	  /** Pre-insert input gain */
15	  readonly inputGain: GainNode;
16	  /** Ordered insert chain (empty initially) */
17	  readonly inserts: readonly InsertSlot[];
18	  /** Post-insert fader (logarithmic taper via GainNode) */
19	  readonly faderGain: GainNode;
20	  /** Stereo panner */
21	  readonly panner: StereoPannerNode;
22	  /** Mute control (gain 0 or 1) */
23	  readonly muteGain: GainNode;
24	  /** AnalyserNode for metering */
25	  readonly analyser: AnalyserNode;
26	  /** Whether this channel is muted */
27	  muted: boolean;
28	  /** Whether this channel is soloed */
29	  solo: boolean;
30	  /** Whether this channel has solo-isolate enabled */
31	  soloIsolate: boolean;
32	};
33	
34	export type MasterBus = {
35	  /** Sum input from all channel strips */
36	  readonly inputGain: GainNode;
37	  /** Master fader */
38	  readonly faderGain: GainNode;
39	  /**
40	   * INV-2: Non-bypassable brickwall limiter.
41	   * DynamicsCompressorNode: threshold=-1dBFS, ratio=20:1, knee=0,
42	   * attack=0.001s, release=0.01s
43	   */
44	  readonly limiter: DynamicsCompressorNode;
45	  /** Master analyser for metering */
46	  readonly analyser: AnalyserNode;
47	};
48	
49	export type MixerEngine = {
50	  /** Get or create a channel strip for a track */
51	  getOrCreateStrip(trackId: string): ChannelStrip;
52	  /** Remove a channel strip */
53	  removeStrip(trackId: string): void;
54	  /** Get an existing strip */
55	  getStrip(trackId: string): ChannelStrip | undefined;
56	  /** Get all channel strips */
57	  getAllStrips(): readonly ChannelStrip[];
58	  /** Get master bus */
59	  getMaster(): MasterBus;
60	
61	  /** Set fader level (0..2, logarithmic taper applied internally) */
62	  setFaderLevel(trackId: string, level: number): void;
63	  /** Set pan (-1..1) */
64	  setPan(trackId: string, pan: number): void;
65	  /** Set mute state */
66	  setMute(trackId: string, muted: boolean): void;
67	  /** Set solo state */
68	  setSolo(trackId: string, solo: boolean): void;
69	  /** Set solo-isolate state */
70	  setSoloIsolate(trackId: string, enabled: boolean): void;
71	  /** Set master fader level */
72	  setMasterLevel(level: number): void;
73	
74	  /** Recompute mute states based on solo-in-place logic */
75	  updateSoloState(): void;
76	
77	  /** Get the output node to connect sources to for a track */
78	  getTrackInput(trackId: string): AudioNode;
79	
80	  /** Add an effect insert to a track's insert chain */
81	  addInsert(
82	    trackId: string,
83	    id: string,
84	    input: AudioNode,
85	    output: AudioNode,
86	  ): void;
87	  /** Remove an effect insert from a track's insert chain */
88	  removeInsert(trackId: string, insertId: string): void;
89	
90	  /** Emergency mute master */
91	  emergencyMute(): void;
92	  /** Release emergency mute */
93	  releaseEmergencyMute(): void;
94	
95	  /** Dispose all nodes */
96	  dispose(): void;
97	};
