1	/* eslint-disable @typescript-eslint/unbound-method -- vi.fn() mocks are safe to reference unbound */
2	import { describe, it, expect, vi, beforeEach } from "vitest";
3	import { createDrumKit } from "./drum-kit";
4	import { DRUM_INSTRUMENTS } from "./drum-types";
5	import type { DrumInstrumentId } from "./drum-types";
6	import type { MixerEngine } from "@audio/mixer/types";
7	
8	function createMockAudioContext(): AudioContext {
9	  const gainNode = (): object => ({
10	    gain: { value: 1, setValueAtTime: vi.fn(), linearRampToValueAtTime: vi.fn(), exponentialRampToValueAtTime: vi.fn(), cancelScheduledValues: vi.fn() },
11	    connect: vi.fn(),
12	    disconnect: vi.fn(),
13	  });
14	
15	  const filterNode = (): object => ({
16	    frequency: { value: 1000, setValueAtTime: vi.fn() },
17	    type: "lowpass",
18	    Q: { value: 1 },
19	    connect: vi.fn(),
20	    disconnect: vi.fn(),
21	  });
22	
23	  const sourceNode = (): object => ({
24	    buffer: null,
25	    playbackRate: { value: 1, setValueAtTime: vi.fn() },
26	    connect: vi.fn(),
27	    disconnect: vi.fn(),
28	    start: vi.fn(),
29	    stop: vi.fn(),
30	    addEventListener: vi.fn(),
31	  });
32	
33	  return {
34	    currentTime: 0,
35	    sampleRate: 48000,
36	    createGain: vi.fn(() => gainNode()),
37	    createBiquadFilter: vi.fn(() => filterNode()),
38	    createBufferSource: vi.fn(() => sourceNode()),
39	    decodeAudioData: vi.fn(),
40	  } as unknown as AudioContext;
41	}
42	
43	function createSilentBuffer(_ctx: AudioContext): AudioBuffer {
44	  return {
45	    length: 4800,
46	    sampleRate: 48000,
47	    duration: 0.1,
48	    numberOfChannels: 1,
49	    getChannelData: () => new Float32Array(4800),
50	    copyFromChannel: vi.fn(),
51	    copyToChannel: vi.fn(),
52	  } as unknown as AudioBuffer;
53	}
54	
55	describe("createDrumKit", () => {
56	  let ctx: AudioContext;
57	  let samples: Map<DrumInstrumentId, AudioBuffer>;
58	
59	  beforeEach(() => {
60	    ctx = createMockAudioContext();
61	    samples = new Map();
62	    for (const inst of DRUM_INSTRUMENTS) {
63	      samples.set(inst.id, createSilentBuffer(ctx));
64	    }
65	  });
66	
67	  it("creates a drum kit", () => {
68	    const kit = createDrumKit(ctx, samples);
69	    expect(kit).toBeDefined();
70	    expect(typeof kit.trigger).toBe("function");
71	    expect(typeof kit.setParam).toBe("function");
72	    expect(typeof kit.dispose).toBe("function");
